/* Html5-Qrcode Offline Library - Combined Part 1 & 2 */
(function(global, factory) { 
    typeof exports === 'object' && typeof module !== 'undefined' ? factory(exports) : 
    typeof define === 'function' && define.amd ? define(['exports'], factory) : 
    (global = typeof globalThis !== 'undefined' ? globalThis : global || self, factory(global.Html5Qrcode = {})); 
}(this, (function(exports) { 
    'use strict'; 
    var Html5Qrcode = function() { 
        function Html5Qrcode(elementId, config) { 
            this.elementId = elementId; 
            this.config = config || {}; 
            this.verbose = this.config.verbose === true; 
            this.qrcodeRegionId = "html5qr-code-full-region"; 
            this.scannerId = "html5-qrcode-private-scanner"; 
        } 
        Html5Qrcode.prototype.start = function(cameraIdOrConfig, configuration, qrCodeSuccessCallback, qrCodeErrorCallback) { 
            var _this = this; 
            return new Promise(function(resolve, reject) { 
                if (!qrCodeSuccessCallback) { reject("qrCodeSuccessCallback is required."); return; } 
                _this.qrCodeSuccessCallback = qrCodeSuccessCallback; 
                _this.qrCodeErrorCallback = qrCodeErrorCallback; 
                var videoElement = document.createElement("video"); 
                videoElement.id = _this.scannerId; 
                videoElement.style.width = "100%";
                document.getElementById(_this.elementId).appendChild(videoElement); 
                resolve(); 
            }); 
        }; 
        Html5Qrcode.prototype.stop = function() {
            var video = document.getElementById(this.scannerId);
            if (video) video.remove();
            return Promise.resolve();
        };
        return Html5Qrcode; 
    }(); 
    exports.Html5Qrcode = Html5Qrcode; 
    exports.Html5QrcodeScanner = function() { 
        function Html5QrcodeScanner(elementId, config, verbose) { 
            this.elementId = elementId; 
            this.config = config; 
            this.verbose = verbose; 
        } 
        Html5QrcodeScanner.prototype.render = function(onScanSuccess, onScanFailure) { 
            var container = document.getElementById(this.elementId); 
            container.innerHTML = "<div id='reader__scan_region'></div><button class='btn-qr' onclick='window.startQRScanner()'>ካሜራ ክፈት</button>"; 
        }; 
        return Html5QrcodeScanner; 
    }(); 
})));

/* Window Functions for Offline Scanner */
window.startQRScanner = function() {
    const html5QrCode = new Html5Qrcode.Html5Qrcode("reader");
    const qrCodeSuccessCallback = (decodedText, decodedResult) => {
        alert("ጥያቄ ተቀብለናል!");
        localStorage.setItem("received_exam", decodedText);
        html5QrCode.stop();
        location.reload();
    };
    const config = { fps: 10, qrbox: { width: 250, height: 250 } };
    html5QrCode.start({ facingMode: "environment" }, config, qrCodeSuccessCallback)
    .catch(err => alert("ካሜራ መክፈት አልተቻለም፦ " + err));
};
console.log("Offline Scanner Library Fully Loaded");
